import React, { useState, useEffect } from "react";
import { motion } from "framer-motion";
import {
  signInWithEmailAndPassword,
  createUserWithEmailAndPassword,
  signOut,
  onAuthStateChanged,
  signInWithPopup,
} from "firebase/auth";
import { auth, googleProvider } from "../firebase";

export default function Home() {
  // 🔐 Authentication States
  const [user, setUser] = useState(null);
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [authMode, setAuthMode] = useState("login");
  const [loading, setLoading] = useState(false);

  // 🧠 Listen for Login Persistence
  useEffect(() => {
    const unsubscribe = onAuthStateChanged(auth, (currentUser) => {
      setUser(currentUser);
    });
    return () => unsubscribe();
  }, []);

  // 🔑 Email/Password Authentication
  const handleAuth = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      if (authMode === "login") {
        await signInWithEmailAndPassword(auth, email, password);
      } else {
        await createUserWithEmailAndPassword(auth, email, password);
      }
      setEmail("");
      setPassword("");
    } catch (error) {
      alert(error.message);
    } finally {
      setLoading(false);
    }
  };

  // 🌐 Google Authentication
  const handleGoogleLogin = async () => {
    try {
      await signInWithPopup(auth, googleProvider);
    } catch (error) {
      alert(error.message);
    }
  };

  // 🚪 Logout
  const handleLogout = async () => {
    await signOut(auth);
  };

  // 🌍 Conditional Rendering
  if (!user) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-light text-primary px-4">
        <motion.div
          initial={{ opacity: 0, y: 30 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.5 }}
          className="bg-white shadow-card rounded-2xl p-8 w-full max-w-md"
        >
          <h1 className="text-3xl font-bold text-center mb-6 text-primary">
            Godemar’s Empire
          </h1>
          <p className="text-center text-muted mb-8">
            {authMode === "login"
              ? "Welcome back! Sign in to explore the creative hub."
              : "Join the Godemar community — where ideas meet opportunity."}
          </p>

          {/* 🔤 Auth Form */}
          <form onSubmit={handleAuth} className="space-y-4">
            <input
              type="email"
              placeholder="Email address"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              required
              className="w-full border border-gray-300 rounded-lg px-4 py-3 focus:outline-none focus:ring-2 focus:ring-accent"
            />
            <input
              type="password"
              placeholder="Password"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              required
              className="w-full border border-gray-300 rounded-lg px-4 py-3 focus:outline-none focus:ring-2 focus:ring-accent"
            />
            <button
              type="submit"
              disabled={loading}
              className="w-full bg-accent text-white font-medium py-3 rounded-lg hover:bg-blue-500 transition"
            >
              {loading
                ? "Processing..."
                : authMode === "login"
                ? "Login"
                : "Sign Up"}
            </button>
          </form>

          {/* 🌐 Google Auth */}
          <button
            onClick={handleGoogleLogin}
            className="w-full mt-4 border border-gray-300 text-primary py-3 rounded-lg hover:bg-gray-50 flex items-center justify-center gap-2"
          >
            <img
              src="https://www.svgrepo.com/show/475656/google-color.svg"
              alt="Google logo"
              className="w-5 h-5"
            />
            Continue with Google
          </button>

          {/* 🔁 Mode Toggle */}
          <p className="text-center text-sm text-muted mt-6">
            {authMode === "login" ? (
              <>
                Don't have an account?{" "}
                <button
                  onClick={() => setAuthMode("signup")}
                  className="text-accent font-medium hover:underline"
                >
                  Sign Up
                </button>
              </>
            ) : (
              <>
                Already have an account?{" "}
                <button
                  onClick={() => setAuthMode("login")}
                  className="text-accent font-medium hover:underline"
                >
                  Login
                </button>
              </>
            )}
          </p>
        </motion.div>
      </div>
    );
  }

  // 🏠 Authenticated Main Hub Layout
  return (
    <div className="min-h-screen bg-light text-primary flex flex-col">
      {/* 🔝 Navbar */}
      <header className="bg-white shadow-soft px-6 py-4 flex justify-between items-center">
        <h1 className="text-2xl font-bold">Godemar’s Empire</h1>
        <nav className="space-x-4 hidden md:flex">
          <button className="text-accent hover:underline">Home</button>
          <button className="text-muted hover:text-accent">Reels</button>
          <button className="text-muted hover:text-accent">Shop</button>
          <button className="text-muted hover:text-accent">Community</button>
          <button className="text-muted hover:text-accent">Profile</button>
        </nav>
        <button
          onClick={handleLogout}
          className="bg-accent text-white px-4 py-2 rounded-lg hover:bg-blue-500 transition"
        >
          Logout
        </button>
      </header>

      {/* 📱 Mobile Menu */}
      <nav className="md:hidden flex justify-around bg-white py-3 shadow-soft fixed bottom-0 left-0 right-0">
        <button className="text-accent">🏠</button>
        <button>🎬</button>
        <button>🛍️</button>
        <button>💬</button>
        <button>👤</button>
      </nav>

      {/* 🧩 Main Content */}
      <main className="flex-grow p-6 md:p-10">
        <motion.section
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.4 }}
          className="max-w-3xl mx-auto text-center"
        >
          <h2 className="text-3xl font-bold mb-3">Welcome, {user.email}</h2>
          <p className="text-muted mb-6">
            Explore creative projects, share ideas, and collaborate with
            innovators across the globe.
          </p>

          {/* 🔄 Placeholder Feed Section */}
          <div className="grid gap-6">
            <div className="bg-white shadow-card rounded-2xl p-6">
              <h3 className="text-xl font-semibold mb-2">Sample Post</h3>
              <p className="text-muted">
                This is a placeholder for your social feed — soon, users will
                share their works, projects, and inspiration here.
              </p>
            </div>

            <div className="bg-white shadow-card rounded-2xl p-6">
              <h3 className="text-xl font-semibold mb-2">E-Commerce Feature</h3>
              <p className="text-muted">
                Buy, sell, and promote creative products and fashion ideas
                seamlessly within Godemar’s Empire.
              </p>
            </div>
          </div>
        </motion.section>
      </main>
    </div>
  );
}
